import { Hono } from 'hono';
import { Context } from 'hono/types';

const app = new Hono();

app.get('/task/:taskId/audit-log', async (c: Context) => {
  const taskId = c.req.param('taskId');

  // Simulate fetching audit log data from a database
  const auditLogData = await fetchAuditLogForTask(taskId);

  if (!auditLogData) {
    return c.json({ error: 'Task not found' }, 404);
  }

  return c.json(auditLogData, 200);
});

async function fetchAuditLogForTask(taskId: string): Promise<any | null> {
  // Replace this with actual database query logic
  const mockAuditLog = [
    { taskId: '1', action: 'created', timestamp: new Date().toISOString() },
    { taskId: '1', action: 'reassigned to John Doe', timestamp: new Date(new Date().getTime() + 3600000).toISOString() },
    { taskId: '1', action: 'status changed to in progress', timestamp: new Date(new Date().getTime() + 7200000).toISOString() }
  ];

  return mockAuditLog.filter(log => log.taskId === taskId);
}

export default app;

